<?php
namespace App\Http\Controllers; use App\Models\{Account,ExchangeTransaction,CurrencyRate}; use Illuminate\Http\Request; use Illuminate\Support\Facades\DB;
class ExchangeTransactionController extends Controller {
    public function create(){ $accounts=Account::orderBy('name')->get(); $rate=CurrencyRate::where('active',true)->orderByDesc('valid_from')->first(); return view('exchange.create',compact('accounts','rate')); }
    public function store(Request $r){ $data=$r->validate(['origin_id'=>'required|exists:tenant.accounts,id','target_id'=>'required|exists:tenant.accounts,id','direction'=>'required|in:usd_to_ves,ves_to_usd','amount'=>'required|numeric|min:0.01','rate'=>'required|numeric|min:0.0001','reference'=>'nullable|string|max:200']); $usedRate=(float)$data['rate']; $origin=Account::findOrFail($data['origin_id']); $target=Account::findOrFail($data['target_id']); if($data['direction']==='usd_to_ves' && $origin->balance_usd < $data['amount']){ return back()->withErrors(['amount'=>'Fondos insuficientes en USD (disponible: '.number_format($origin->balance_usd,2).')'])->withInput(); } if($data['direction']==='ves_to_usd' && $origin->balance_ves < $data['amount']){ return back()->withErrors(['amount'=>'Fondos insuficientes en VES (disponible: '.number_format($origin->balance_ves,2).')'])->withInput(); } DB::transaction(function() use($data,$usedRate,$origin,$target){ if($data['direction']==='usd_to_ves'){ $usd=$data['amount']; $ves=round($usd*$usedRate,2); $origin->decrement('balance_usd',$usd); $target->increment('balance_ves',$ves); ExchangeTransaction::create(['account_origin_id'=>$origin->id,'account_target_id'=>$target->id,'rate'=>$usedRate,'amount_origin_usd'=>$usd,'amount_origin_ves'=>0,'amount_target_usd'=>0,'amount_target_ves'=>$ves]); } else { $ves=$data['amount']; $usd=round($ves/$usedRate,2); $origin->decrement('balance_ves',$ves); $target->increment('balance_usd',$usd); ExchangeTransaction::create(['account_origin_id'=>$origin->id,'account_target_id'=>$target->id,'rate'=>$usedRate,'amount_origin_usd'=>0,'amount_origin_ves'=>$ves,'amount_target_usd'=>$usd,'amount_target_ves'=>0]); } }); return redirect()->route('accounts.index')->with('status','Cambio realizado'); }
}
